void solve(int CASE)
{
	int n, m, k; cin >> n >> m >> k;
	var a = vector<int>(n);
	fa(i, 0, n - 1)cin >> a[i];

	if (m >= n) {
		fa(i, 0, n - 1)if (a[i] == k) {
			cout << 0 << endl;
			return;
		}
		cout << 1 << endl;
		return;
	}

	var f = [&](int m)->int {
		// 直接暴力算答案 O(n)
		var cnt = vector<int>(m);
		fa(i, 0, n - 1)if (a[i] == k)cnt[i % m]++;
		int ans = INF;
		fa(i, 0, m - 1) {
			int len = n / m;
			if (n % m >= i + 1)len++;
			ans = min(ans, len - cnt[i]);
		}
		return ans;
		};

	// 两个外层循环复杂度均为 O(根号n)
	int ans = INF;
	for (int i = m; i <= n and i - m <= ans; i++)ans = min(ans, f(i) + i - m);
	for (int i = m; i >= 1 and m - i <= ans; i--)ans = min(ans, f(i) + m - i);
	cout << ans << endl;
	return;
}
